project_name = #{projectName}, project_code = #{projectCode}, description = #{description}, status = #{status}, priority = #{priority}, budget = #{budget}, requirement_count = #{requirementCount}, investment = #{investment}, start_date = #{startDate}, end_date = #{endDate}, real_start_date = #{realStartDate}, real_end_date = #{realEndDate}, progress = #{progress}, owner_id = #{ownerId}, owner_name = #{ownerName}, team_id = #{teamId}, board_style = #{boardStyle}, col_width = #{colWidth}, display_cards = #{displayCards}, fluid_board = #{fluidBoard}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime}, del_flag = #{delFlag},
